functions.longDescription:
Append one byte when capacity remains.

Workflow example preserved from the former snippet:

#define RING_CAPACITY 256U

typedef struct ByteRing
{
    unsigned char data[RING_CAPACITY];
    size_t head;
    size_t tail;
    size_t count;
} ByteRing;

int ByteRing_Push(ByteRing *ring, unsigned char value)
{
    if (ring->count == RING_CAPACITY) return -1;
    ring->data[ring->head] = value;
    ring->head = (ring->head + 1U) % RING_CAPACITY;
    ++ring->count;
    return 0;
}

functions.signature:
#include <stdint.h>
#include <stddef.h>

typedef struct DmaNode
{
    uint8_t *data;
    uint16_t size;
    uint16_t flags;
} DmaNode;

typedef struct DmaRing
{
    DmaNode nodes[8];
    volatile uint16_t head;
    volatile uint16_t tail;
} DmaRing;

static int DmaRing_Push(DmaRing *ring, DmaNode node)
{
    uint16_t next = (uint16_t)((ring->head + 1u) % 8u);
    if (next == ring->tail)
    {
        return -1; /* full */
    }

    ring->nodes[ring->head] = node;
    ring->head = next;
    return 0;
}

