static bool Size_AddOverflow(
    size_t lhs,
    size_t rhs,
    size_t *result
)
{
    if (lhs > SIZE_MAX - rhs)
    {
        return true;
    }

    *result = lhs + rhs;
    return false;
}

static bool Size_MulOverflow(
    size_t lhs,
    size_t rhs,
    size_t *result
)
{
    if (rhs != 0 && lhs > SIZE_MAX / rhs)
    {
        return true;
    }

    *result = lhs * rhs;
    return false;
}

