functions.insertText:
#include <windows.h>

BOOL APIENTRY DllMain(HMODULE hModule, DWORD ul_reason_for_call, LPVOID lpReserved)
{
    (void)lpReserved;

    if (ul_reason_for_call == DLL_PROCESS_ATTACH)
    {
        /* Use only when DLL_THREAD_ATTACH / DLL_THREAD_DETACH callbacks are not required. */
        DisableThreadLibraryCalls({{module}});
    }

    return TRUE;
}

#include <windows.h>

typedef int (WINAPI *PluginRunFn)(int value);

HMODULE module = LoadLibraryExW(
    {{libraryPath}},
    NULL,
    LOAD_LIBRARY_SEARCH_DLL_LOAD_DIR | LOAD_LIBRARY_SEARCH_DEFAULT_DIRS);
if (module == NULL)
{
    return -1;
}

PluginRunFn run = (PluginRunFn)GetProcAddress(module, {{procedureName}});
if (run == NULL)
{
    FreeLibrary(module);
    return -1;
}

int result = run({{argument}});
FreeLibrary(module);

